1	import { describe, it, expect } from "vitest";
2	import { quote, claim } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office — quote", () => {
5	  // Simplest case
6	  it("empty item list → premium 5 G (only processing fee)", () => {
7	    expect(quote({ yearsWithMHPCO: 0 }, [], 0)).toBe(5);
8	  });
9	
10	  // Base premiums per item type (newcomer, no modifiers beyond first insurance & fee)
11	  it("single plain sword for newcomer (no prior contracts) → base 100 + 10 first + 5 fee = 115 G", () => {
12	    expect(quote({ yearsWithMHPCO: 0 }, [{ type: "sword" }], 0)).toBe(115);
13	  });
14	  it("single plain amulet for newcomer → base 60 + 6 first + 5 fee = 71 G", () => {
15	    expect(quote({ yearsWithMHPCO: 0 }, [{ type: "amulet" }], 0)).toBe(71);
16	  });
17	  it("single plain staff for newcomer → base 80 + 8 first + 5 fee = 93 G", () => {
18	    expect(quote({ yearsWithMHPCO: 0 }, [{ type: "staff" }], 0)).toBe(93);
19	  });
20	  it("single plain potion for newcomer → base 40 + 4 first + 5 fee = 49 G", () => {
21	    expect(quote({ yearsWithMHPCO: 0 }, [{ type: "potion" }], 0)).toBe(49);
22	  });
23	
24	  // Components — base premiums (newcomer; verifying base before block rule)
25	  it("2 runes → base 50 G (no block; +5 first +5 fee = 60 G)", () => {
26	    expect(quote({ yearsWithMHPCO: 0 }, [{ type: "rune" }, { type: "rune" }], 0)).toBe(60);
27	  });
28	  it("3 runes → base 60 G via block (+6 first +5 fee = 71 G)", () => {
29	    expect(quote({ yearsWithMHPCO: 0 }, [{ type: "rune" }, { type: "rune" }, { type: "rune" }], 0)).toBe(71);
30	  });
31	  it.todo("4 runes → base 100 G (no block; block requires exactly 3) → +10 first +5 fee = 115 G");
32	  it.todo("7 runes → base 175 G");
33	
34	  // "Alike" components clarification
35	  it.todo("2 runes + 1 moonstone → base 75 G (no block — different types)");
36	  it.todo("3 runes + 3 moonstones → base 120 G (two separate blocks)");
37	
38	  // Item-specific modifiers
39	  it.todo("cursed sword for newcomer → 100 + 50 curse + 10 first + 5 fee = 165 G");
40	  it.todo("sword with enchantment exactly 5 (newcomer) → 100 + 30 high-ench + 10 first + 5 fee = 145 G");
41	  it.todo("sword with enchantment 4 (newcomer) → no high-ench surcharge → 115 G");
42	  it.todo("cursed sword with enchantment 5 (newcomer) → both surcharges apply");
43	
44	  // Modifier scope on multi-item policies (clarifying question ❓)
45	  it.todo("policy: cursed sword + plain amulet → 210 G before further modifiers and fee (newcomer additions extra)");
46	
47	  // Loyalty discount threshold
48	  it.todo("customer with exactly 2 years → loyalty discount applies (20% of policy base)");
49	  it.todo("customer with 1 year → no loyalty discount");
50	
51	  // Follow-up contract discount (each contract after the first → 15% off policy base)
52	  it.todo("second contract for same customer in same scenario → 15% follow-up discount applies");
53	
54	  // First insurance per item, regardless of customer history (❓ clarification)
55	  it.todo("long-standing customer's second contract: cursed sword ench 7 → premium 160 G (matches spec integration example)");
56	
57	  // Rounding in MHPCO's favor
58	  it.todo("premium calculation yielding 197.5 → final premium 198 (rounded up)");
59	
60	  // Errors
61	  it.todo("unknown item type in quote → throws error");
62	});
63	
64	describe("MHPCO Claim Office — claim", () => {
65	  // Standard reimbursement (no special clauses)
66	  it.todo("regular steel sword ench 3, damage 500 → payout 400 (500 − 100 deductible)");
67	  it.todo("rune (no enchantment / material), damage 200 → payout 100 (200 − 100 deductible)");
68	
69	  // Enchantment ≥8 clause
70	  it.todo("steel sword ench 9, damage 1000 → payout 400 (50% then deductible)");
71	
72	  // Dragon material clause
73	  it.todo("dragon-material sword ench 5, damage 800 → payout 700 (full, then deductible)");
74	
75	  // Both clauses — 50% wins, then deductible
76	  it.todo("dragon-material sword ench 9, damage 1000 → payout 400");
77	  it.todo("dragon-material sword ench exactly 8, damage 1000 → payout 400 (high-ench applies, then deductible)");
78	
79	  // Deductible per damage event
80	  it.todo("dragon attack damaging sword 500 + amulet 300 → payout 600 (deductible per item)");
81	
82	  // Multiple items of same type
83	  it.todo("policy with two swords; damage to both → each treated as separate damage with own deductible");
84	  it.todo("damages array has more entries of a type than the policy covers → throws error");
85	
86	  // Cap exhaustion
87	  it.todo("policy: sword + amulet → insurance sum 1600, cap 3200");
88	  it.todo("policy: cursed sword → cap 2000 (based on unmodified insurance value)");
89	  it.todo("policy: sword + 3 runes (block) → insurance sum 1750 (block doesn't affect sum)");
90	  it.todo("sword (cap 2000), first claim 1500 → payout 1400, remaining 600; second claim 1500 → payout 600, remaining 0");
91	
92	  // Rounding for payouts
93	  it.todo("payout calculation yielding 350.5 → final payout 350 (rounded down)");
94	
95	  // Errors
96	  it.todo("claim references damage for an item not in the policy → throws error");
97	  it.todo("claim contains damage with negative amount → throws error");
98	});
