1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	}
8	
9	export interface Damage {
10	  itemType: string;
11	  amount: number;
12	}
13	
14	export interface Incident {
15	  cause: string;
16	  damages: Damage[];
17	}
18	
19	export interface Policy {
20	  items: Item[];
21	  insuranceSum: number;
22	  cap: number;
23	  remainingCap: number;
24	}
25	
26	const PROCESSING_FEE = 5;
27	const FIRST_INSURANCE_RATE = 0.1;
28	
29	const BASE_PREMIUM: Record<string, number> = {
30	  sword: 100,
31	  amulet: 60,
32	  staff: 80,
33	  potion: 40,
34	  rune: 25,
35	};
36	
37	const COMPONENT_TYPES = new Set(["rune"]);
38	const BLOCK_BASE = 60;
39	
40	const baseForGroup = (type: string, count: number): number => {
41	  if (COMPONENT_TYPES.has(type) && count === 3) return BLOCK_BASE;
42	  return BASE_PREMIUM[type] * count;
43	};
44	
45	const groupByType = (items: Item[]): Map<string, number> => {
46	  const counts = new Map<string, number>();
47	  for (const item of items) {
48	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
49	  }
50	  return counts;
51	};
52	
53	export const quote = (
54	  _customer: Customer,
55	  items: Item[],
56	  _priorContracts: number,
57	): number => {
58	  const groups = groupByType(items);
59	  let itemsTotal = 0;
60	  for (const [type, count] of groups) {
61	    const base = baseForGroup(type, count);
62	    itemsTotal += base + base * FIRST_INSURANCE_RATE;
63	  }
64	  return itemsTotal + PROCESSING_FEE;
65	};
66	
67	export const claim = (
68	  _policy: Policy,
69	  _incident: Incident,
70	): { payout: number; remainingCap: number } => {
71	  return undefined as unknown as { payout: number; remainingCap: number };
72	};
73

