const countByType = (items: Item[]): Map<string, number> => {
  const counts = new Map<string, number>();
  for (const item of items) {
    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
  }
  return counts;
};

const withFirstInsurance = (base: number): number =>
  base + base * FIRST_INSURANCE_RATE;

export const quote = (
  _customer: Customer,
  items: Item[],
  _priorContracts: number,
): number => {
  let itemsTotal = 0;
  for (const [type, count] of countByType(items)) {
    itemsTotal += withFirstInsurance(baseForGroup(type, count));
  }
  return itemsTotal + PROCESSING_FEE;
};

